from dataclasses import dataclass, field
from datetime import datetime
from typing import Optional

@dataclass
class TimelineEntry:
    time: datetime
    event: str
    actor: str          # 'System' or engineer name
    is_anchor: bool = False
    anchor_label: Optional[str] = None

@dataclass
class PostmortemDraft:
    incident_id: str
    title: str
    severity: int
    start_time: datetime
    resolution_time: datetime
    owner: str
    timeline: list[TimelineEntry] = field(default_factory=list)
    impact_summary: str = ''
    root_cause: str = ''
    contributing_factors: list[str] = field(default_factory=list)
    action_items: list[dict] = field(default_factory=list)

    @property
    def duration_minutes(self) -> int:
        return int((self.resolution_time - self.start_time).total_seconds() / 60)

    def anchor_events(self) -> list[TimelineEntry]:
        return [e for e in self.timeline if e.is_anchor]

    def to_markdown(self) -> str:
        timeline_rows = '\n'.join(
            f'| {e.time.strftime("%H:%M")} | {e.event} | {e.actor} |'
            for e in sorted(self.timeline, key=lambda x: x.time)
        )
        factors = '\n'.join(f'- {f}' for f in self.contributing_factors)
        actions = '\n'.join(
            f'| {i+1} | {a["description"]} | {a["category"]} | '
            f'{a.get("owner", "TBD")} | {a.get("target", "TBD")} | {a.get("ticket", "TBD")} |'
            for i, a in enumerate(self.action_items)
        )
        return f"""# Postmortem: {self.title}
**Incident:** {self.incident_id} | **SEV:** {self.severity} | **Owner:** {self.owner}

## Impact
- Duration: {self.duration_minutes} min
- {self.impact_summary}

## Timeline (UTC)
| Time | Event | Actor |
|------|-------|-------|
{timeline_rows}

## Root Cause
{self.root_cause}

**Contributing factors:**
{factors}

## Action Items
| # | Description | Category | Owner | Target | Ticket |
|---|-------------|----------|-------|--------|--------|
{actions}
"""


def create_draft_from_incident(incident_data: dict) -> PostmortemDraft:
    """Populate a PostmortemDraft from incident management platform export."""
    draft = PostmortemDraft(
        incident_id=incident_data['id'],
        title=f"{incident_data['service']} — {incident_data['title']}",
        severity=incident_data['severity'],
        start_time=datetime.fromisoformat(incident_data['declared_at']),
        resolution_time=datetime.fromisoformat(incident_data['resolved_at']),
        owner=incident_data['ic'],
    )
    for entry in incident_data.get('timeline', []):
        draft.timeline.append(TimelineEntry(
            time=datetime.fromisoformat(entry['time']),
            event=entry['text'],
            actor=entry.get('author', 'System'),
            is_anchor=entry.get('is_anchor', False),
            anchor_label=entry.get('anchor_label'),
        ))
    return draft
